void solve(int CASE)
{
	ll n; cin >> n;
	var a = vector<ll>(n + 1);
	fa(i, 1, n)cin >> a[i];
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}

	var down = vector<ll>(n + 1);
	var sum = vector<ll>(n + 1);
	var dfs = [&](var dfs, int now, int fa)->void {
		sum[now] = a[now];
		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);
			down[now] += down[to] + sum[to];
			sum[now] += sum[to];
		}
		};
	dfs(dfs, 1, 0);

	ll ans = 0;
	var dfss = [&](var dfs, int now, int fa, ll up)->void {
		ll res = up + down[now];
		ans = max(ans, res);
		for (int to : g[now]) {
			if (to == fa)continue;
			ll nup = down[now] - down[to] - sum[to] + sum[now] - sum[to] + up + sum[1] - sum[now];
			dfs(dfs, to, now, nup);
		}
		};
	dfss(dfss, 1, 0, 0);
	cout << ans << endl;
	return;
}
